SELECT "W_WAREHOUSE_NAME00" AS "W_WAREHOUSE_NAME", "W_WAREHOUSE_SQ_FT00" AS "W_WAREHOUSE_SQ_FT", "W_CITY00" AS "W_CITY", "W_COUNTY00" AS "W_COUNTY", "W_STATE00" AS "W_STATE", "W_COUNTRY00" AS "W_COUNTRY", "$f37" AS "SHIP_CARRIERS", "D_YEAR00" AS "YEAR_VAL", SUM("$f70") AS "JAN_SALES", SUM("$f80") AS "FEB_SALES", SUM("$f90") AS "MAR_SALES", SUM("$f100") AS "APR_SALES", SUM("$f110") AS "MAY_SALES", SUM("$f120") AS "JUN_SALES", SUM("$f130") AS "JUL_SALES", SUM("$f140") AS "AUG_SALES", SUM("$f150") AS "SEP_SALES", SUM("$f160") AS "OCT_SALES", SUM("$f170") AS "NOV_SALES", SUM("$f180") AS "DEC_SALES", SUM("$f70" / CAST("W_WAREHOUSE_SQ_FT00" AS DECIMAL(17, 2))) AS "JAN_SALES_PER_SQ_FOOT", SUM("$f80" / CAST("W_WAREHOUSE_SQ_FT00" AS DECIMAL(17, 2))) AS "FEB_SALES_PER_SQ_FOOT", SUM("$f90" / CAST("W_WAREHOUSE_SQ_FT00" AS DECIMAL(17, 2))) AS "MAR_SALES_PER_SQ_FOOT", SUM("$f100" / CAST("W_WAREHOUSE_SQ_FT00" AS DECIMAL(17, 2))) AS "APR_SALES_PER_SQ_FOOT", SUM("$f110" / CAST("W_WAREHOUSE_SQ_FT00" AS DECIMAL(17, 2))) AS "MAY_SALES_PER_SQ_FOOT", SUM("$f120" / CAST("W_WAREHOUSE_SQ_FT00" AS DECIMAL(17, 2))) AS "JUN_SALES_PER_SQ_FOOT", SUM("$f130" / CAST("W_WAREHOUSE_SQ_FT00" AS DECIMAL(17, 2))) AS "JUL_SALES_PER_SQ_FOOT", SUM("$f140" / CAST("W_WAREHOUSE_SQ_FT00" AS DECIMAL(17, 2))) AS "AUG_SALES_PER_SQ_FOOT", SUM("$f150" / CAST("W_WAREHOUSE_SQ_FT00" AS DECIMAL(17, 2))) AS "SEP_SALES_PER_SQ_FOOT", SUM("$f160" / CAST("W_WAREHOUSE_SQ_FT00" AS DECIMAL(17, 2))) AS "OCT_SALES_PER_SQ_FOOT", SUM("$f170" / CAST("W_WAREHOUSE_SQ_FT00" AS DECIMAL(17, 2))) AS "NOV_SALES_PER_SQ_FOOT", SUM("$f180" / CAST("W_WAREHOUSE_SQ_FT00" AS DECIMAL(17, 2))) AS "DEC_SALES_PER_SQ_FOOT", SUM("$f190") AS "JAN_NET", SUM("$f200") AS "FEB_NET", SUM("$f210") AS "MAR_NET", SUM("$f220") AS "APR_NET", SUM("$f230") AS "MAY_NET", SUM("$f240") AS "JUN_NET", SUM("$f250") AS "JUL_NET", SUM("$f260") AS "AUG_NET", SUM("$f270") AS "SEP_NET", SUM("$f280") AS "OCT_NET", SUM("$f290") AS "NOV_NET", SUM("$f300") AS "DEC_NET"
FROM (SELECT "WAREHOUSE"."W_WAREHOUSE_NAME" AS "W_WAREHOUSE_NAME00", "WAREHOUSE"."W_WAREHOUSE_SQ_FT" AS "W_WAREHOUSE_SQ_FT00", "WAREHOUSE"."W_CITY" AS "W_CITY00", "WAREHOUSE"."W_COUNTY" AS "W_COUNTY00", "WAREHOUSE"."W_STATE" AS "W_STATE00", "WAREHOUSE"."W_COUNTRY" AS "W_COUNTRY00", CAST('DHL' || ',' AS VARCHAR(6)) || 'BARIAN' AS "$f37", "DATE_DIM"."D_YEAR" AS "D_YEAR00", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 1 THEN "WEB_SALES"."WS_EXT_SALES_PRICE" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f70", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 2 THEN "WEB_SALES"."WS_EXT_SALES_PRICE" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f80", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 3 THEN "WEB_SALES"."WS_EXT_SALES_PRICE" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f90", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 4 THEN "WEB_SALES"."WS_EXT_SALES_PRICE" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f100", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 5 THEN "WEB_SALES"."WS_EXT_SALES_PRICE" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f110", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 6 THEN "WEB_SALES"."WS_EXT_SALES_PRICE" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f120", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 7 THEN "WEB_SALES"."WS_EXT_SALES_PRICE" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f130", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 8 THEN "WEB_SALES"."WS_EXT_SALES_PRICE" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f140", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 9 THEN "WEB_SALES"."WS_EXT_SALES_PRICE" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f150", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 10 THEN "WEB_SALES"."WS_EXT_SALES_PRICE" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f160", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 11 THEN "WEB_SALES"."WS_EXT_SALES_PRICE" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f170", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 12 THEN "WEB_SALES"."WS_EXT_SALES_PRICE" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f180", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 1 THEN "WEB_SALES"."WS_NET_PAID_INC_SHIP_TAX" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f190", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 2 THEN "WEB_SALES"."WS_NET_PAID_INC_SHIP_TAX" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f200", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 3 THEN "WEB_SALES"."WS_NET_PAID_INC_SHIP_TAX" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f210", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 4 THEN "WEB_SALES"."WS_NET_PAID_INC_SHIP_TAX" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f220", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 5 THEN "WEB_SALES"."WS_NET_PAID_INC_SHIP_TAX" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f230", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 6 THEN "WEB_SALES"."WS_NET_PAID_INC_SHIP_TAX" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f240", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 7 THEN "WEB_SALES"."WS_NET_PAID_INC_SHIP_TAX" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f250", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 8 THEN "WEB_SALES"."WS_NET_PAID_INC_SHIP_TAX" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f260", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 9 THEN "WEB_SALES"."WS_NET_PAID_INC_SHIP_TAX" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f270", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 10 THEN "WEB_SALES"."WS_NET_PAID_INC_SHIP_TAX" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f280", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 11 THEN "WEB_SALES"."WS_NET_PAID_INC_SHIP_TAX" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f290", SUM(CASE WHEN "DATE_DIM"."D_MOY" = 12 THEN "WEB_SALES"."WS_NET_PAID_INC_SHIP_TAX" * CAST("WEB_SALES"."WS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f300"
FROM "tpcds"."WEB_SALES",
"tpcds"."WAREHOUSE",
"tpcds"."DATE_DIM",
"tpcds"."TIME_DIM",
"tpcds"."SHIP_MODE"
WHERE "WEB_SALES"."WS_WAREHOUSE_SK" = "WAREHOUSE"."W_WAREHOUSE_SK" AND "WEB_SALES"."WS_SOLD_DATE_SK" = "DATE_DIM"."D_DATE_SK" AND ("WEB_SALES"."WS_SOLD_TIME_SK" = "TIME_DIM"."T_TIME_SK" AND "WEB_SALES"."WS_SHIP_MODE_SK" = "SHIP_MODE"."SM_SHIP_MODE_SK") AND ("DATE_DIM"."D_YEAR" = 1998 AND "TIME_DIM"."T_TIME" >= 56546 AND ("TIME_DIM"."T_TIME" <= 56546 + 28800 AND CAST("SHIP_MODE"."SM_CARRIER" AS VARCHAR(20)) IN ('BARIAN', 'DHL')))
GROUP BY "WAREHOUSE"."W_WAREHOUSE_NAME", "WAREHOUSE"."W_WAREHOUSE_SQ_FT", "WAREHOUSE"."W_CITY", "WAREHOUSE"."W_COUNTY", "WAREHOUSE"."W_STATE", "WAREHOUSE"."W_COUNTRY", "DATE_DIM"."D_YEAR"
UNION ALL
SELECT "WAREHOUSE0"."W_WAREHOUSE_NAME" AS "W_WAREHOUSE_NAME00", "WAREHOUSE0"."W_WAREHOUSE_SQ_FT" AS "W_WAREHOUSE_SQ_FT00", "WAREHOUSE0"."W_CITY" AS "W_CITY00", "WAREHOUSE0"."W_COUNTY" AS "W_COUNTY00", "WAREHOUSE0"."W_STATE" AS "W_STATE00", "WAREHOUSE0"."W_COUNTRY" AS "W_COUNTRY00", CAST('DHL' || ',' AS VARCHAR(6)) || 'BARIAN' AS "$f37", "DATE_DIM0"."D_YEAR" AS "D_YEAR00", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 1 THEN "CATALOG_SALES"."CS_EXT_SALES_PRICE" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f70", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 2 THEN "CATALOG_SALES"."CS_EXT_SALES_PRICE" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f80", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 3 THEN "CATALOG_SALES"."CS_EXT_SALES_PRICE" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f90", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 4 THEN "CATALOG_SALES"."CS_EXT_SALES_PRICE" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f100", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 5 THEN "CATALOG_SALES"."CS_EXT_SALES_PRICE" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f110", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 6 THEN "CATALOG_SALES"."CS_EXT_SALES_PRICE" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f120", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 7 THEN "CATALOG_SALES"."CS_EXT_SALES_PRICE" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f130", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 8 THEN "CATALOG_SALES"."CS_EXT_SALES_PRICE" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f140", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 9 THEN "CATALOG_SALES"."CS_EXT_SALES_PRICE" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f150", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 10 THEN "CATALOG_SALES"."CS_EXT_SALES_PRICE" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f160", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 11 THEN "CATALOG_SALES"."CS_EXT_SALES_PRICE" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f170", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 12 THEN "CATALOG_SALES"."CS_EXT_SALES_PRICE" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f180", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 1 THEN "CATALOG_SALES"."CS_NET_PAID_INC_TAX" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f190", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 2 THEN "CATALOG_SALES"."CS_NET_PAID_INC_TAX" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f200", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 3 THEN "CATALOG_SALES"."CS_NET_PAID_INC_TAX" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f210", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 4 THEN "CATALOG_SALES"."CS_NET_PAID_INC_TAX" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f220", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 5 THEN "CATALOG_SALES"."CS_NET_PAID_INC_TAX" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f230", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 6 THEN "CATALOG_SALES"."CS_NET_PAID_INC_TAX" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f240", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 7 THEN "CATALOG_SALES"."CS_NET_PAID_INC_TAX" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f250", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 8 THEN "CATALOG_SALES"."CS_NET_PAID_INC_TAX" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f260", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 9 THEN "CATALOG_SALES"."CS_NET_PAID_INC_TAX" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f270", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 10 THEN "CATALOG_SALES"."CS_NET_PAID_INC_TAX" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f280", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 11 THEN "CATALOG_SALES"."CS_NET_PAID_INC_TAX" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f290", SUM(CASE WHEN "DATE_DIM0"."D_MOY" = 12 THEN "CATALOG_SALES"."CS_NET_PAID_INC_TAX" * CAST("CATALOG_SALES"."CS_QUANTITY" AS DECIMAL(12, 2)) ELSE 0.00 END) AS "$f300"
FROM "tpcds"."CATALOG_SALES",
"tpcds"."WAREHOUSE" AS "WAREHOUSE0",
"tpcds"."DATE_DIM" AS "DATE_DIM0",
"tpcds"."TIME_DIM" AS "TIME_DIM0",
"tpcds"."SHIP_MODE" AS "SHIP_MODE0"
WHERE "CATALOG_SALES"."CS_WAREHOUSE_SK" = "WAREHOUSE0"."W_WAREHOUSE_SK" AND "CATALOG_SALES"."CS_SOLD_DATE_SK" = "DATE_DIM0"."D_DATE_SK" AND ("CATALOG_SALES"."CS_SOLD_TIME_SK" = "TIME_DIM0"."T_TIME_SK" AND "CATALOG_SALES"."CS_SHIP_MODE_SK" = "SHIP_MODE0"."SM_SHIP_MODE_SK") AND ("DATE_DIM0"."D_YEAR" = 1998 AND "TIME_DIM0"."T_TIME" >= 56546 AND ("TIME_DIM0"."T_TIME" <= 56546 + 28800 AND CAST("SHIP_MODE0"."SM_CARRIER" AS VARCHAR(20)) IN ('BARIAN', 'DHL')))
GROUP BY "WAREHOUSE0"."W_WAREHOUSE_NAME", "WAREHOUSE0"."W_WAREHOUSE_SQ_FT", "WAREHOUSE0"."W_CITY", "WAREHOUSE0"."W_COUNTY", "WAREHOUSE0"."W_STATE", "WAREHOUSE0"."W_COUNTRY", "DATE_DIM0"."D_YEAR") AS "t7"
GROUP BY "W_WAREHOUSE_NAME00", "W_WAREHOUSE_SQ_FT00", "W_CITY00", "W_COUNTY00", "W_STATE00", "W_COUNTRY00", "$f37", "D_YEAR00"
ORDER BY "W_WAREHOUSE_NAME00"
FETCH NEXT 100 ROWS ONLY
